use std::sync::Arc;
use std::thread;

fn parallel_map<T, R, F>(items: &[T], f: F) -> Vec<R>
where
    T: Send + Clone + 'static,
    R: Send + 'static,
    F: Fn(T) -> R + Send + Sync + 'static,
{
    let f = Arc::new(f);
    items.iter()
        .map(|item| {
            let item = item.clone();
            let f = Arc::clone(&f);
            thread::spawn(move || f(item))
        })
        .map(|h| h.join().unwrap())
        .collect()
}

fn main() {
    let nums = vec![1i32, 2, 3, 4];
    let results = parallel_map(&nums, |x| x * 2);
    println!("{:?}", results);
}

