    // Marker<String>: 'static because String: 'static
    let m1: Marker<String> = Marker(PhantomData);
    require_static(m1); // OK

    // Marker<i32>: 'static because i32: 'static
    let m2: Marker<i32> = Marker(PhantomData);
    require_static(m2); // OK

    // Marker<&'static str>: 'static because &'static str: 'static
    let m3: Marker<&'static str> = Marker(PhantomData);
    require_static(m3); // OK

