fn add(a: i32, b: i32) -> i32 { a + b }
fn mul(a: i32, b: i32) -> i32 { a * b }

// fn items are 'static: they live in the binary's code segment
fn store_fn(f: fn(i32, i32) -> i32) -> Box<dyn Fn(i32, i32) -> i32 + 'static> {
    Box::new(move |a, b| f(a, b))
    // The closure captures `f: fn(i32, i32) -> i32`
    // fn pointer is 'static, so the closure is 'static
}

fn require_static_fn<F: Fn(i32, i32) -> i32 + 'static>(f: F) {
    println!("result: {}", f(10, 5));
}

fn main() {
    let boxed_add = store_fn(add);
    let boxed_mul = store_fn(mul);
    println!("{}", boxed_add(3, 4)); // 7
    println!("{}", boxed_mul(3, 4)); // 12

    // fn pointers themselves are 'static:
    require_static_fn(add);
    require_static_fn(mul);
}
